package he

import (
	"bytes"
	"fmt"

	"github.com/tuneinsight/lattigo/v6/core/rlwe"
	"github.com/tuneinsight/lattigo/v6/schemes/ckks"
)

// EvaluationKeys contains the public evaluation keys (relinearization and galois keys)
// needed by a provider to perform homomorphic operations (Multiply, Rotate) on ciphertexts.
// These are generated by the consumer and sent alongside the inference request.
type EvaluationKeys struct {
	RelinKey   *rlwe.RelinearizationKey
	GaloisKeys []*rlwe.GaloisKey
	params     ckks.Parameters
}

// GenerateEvaluationKeys generates the evaluation keys required for homomorphic
// operations using the consumer's secret key. These keys can be safely shared with providers.
func (kg *KeyGenerator) GenerateEvaluationKeys(sk *SecretKey) (*EvaluationKeys, error) {
	kgen := rlwe.NewKeyGenerator(kg.params)

	// Generate relinearization key for multiplications
	relinKey := kgen.GenRelinearizationKeyNew(sk.sk)

	// Generate galois keys for rotations
	slots := kg.params.MaxSlots()
	rotations := make([]int, slots-1)
	for i := 1; i < slots; i++ {
		rotations[i-1] = i
	}
	galEls := kg.params.GaloisElements(rotations)
	galoisKeys := kgen.GenGaloisKeysNew(galEls, sk.sk)

	return &EvaluationKeys{
		RelinKey:   relinKey,
		GaloisKeys: galoisKeys,
		params:     kg.params,
	}, nil
}

// MarshalBinary serializes the EvaluationKeys into a byte slice.
func (ek *EvaluationKeys) MarshalBinary() ([]byte, error) {
	var buf bytes.Buffer

	// Marshal parameters
	paramBytes, err := ek.params.MarshalBinary()
	if err != nil {
		return nil, fmt.Errorf("failed to marshal params: %w", err)
	}

	// Write params length and data
	paramLen := uint32(len(paramBytes))
	buf.WriteByte(byte(paramLen >> 24))
	buf.WriteByte(byte(paramLen >> 16))
	buf.WriteByte(byte(paramLen >> 8))
	buf.WriteByte(byte(paramLen))
	buf.Write(paramBytes)

	// Marshal RelinKey
	relinBytes, err := ek.RelinKey.MarshalBinary()
	if err != nil {
		return nil, fmt.Errorf("failed to marshal relin key: %w", err)
	}
	
	relinLen := uint32(len(relinBytes))
	buf.WriteByte(byte(relinLen >> 24))
	buf.WriteByte(byte(relinLen >> 16))
	buf.WriteByte(byte(relinLen >> 8))
	buf.WriteByte(byte(relinLen))
	buf.Write(relinBytes)

	// Marshal GaloisKeys
	gkCount := uint32(len(ek.GaloisKeys))
	buf.WriteByte(byte(gkCount >> 24))
	buf.WriteByte(byte(gkCount >> 16))
	buf.WriteByte(byte(gkCount >> 8))
	buf.WriteByte(byte(gkCount))

	for _, gk := range ek.GaloisKeys {
		gkBytes, err := gk.MarshalBinary()
		if err != nil {
			return nil, fmt.Errorf("failed to marshal galois key: %w", err)
		}
		gkLen := uint32(len(gkBytes))
		buf.WriteByte(byte(gkLen >> 24))
		buf.WriteByte(byte(gkLen >> 16))
		buf.WriteByte(byte(gkLen >> 8))
		buf.WriteByte(byte(gkLen))
		buf.Write(gkBytes)
	}

	return buf.Bytes(), nil
}

// UnmarshalBinary deserializes EvaluationKeys from a byte slice.
func (ek *EvaluationKeys) UnmarshalBinary(data []byte) error {
	if len(data) < 4 {
		return fmt.Errorf("data too short for EvaluationKeys")
	}

	offset := 0

	// Read params
	paramLen := uint32(data[offset])<<24 | uint32(data[offset+1])<<16 | uint32(data[offset+2])<<8 | uint32(data[offset+3])
	offset += 4
	if len(data) < offset+int(paramLen) {
		return fmt.Errorf("data truncated while reading params")
	}
	var params ckks.Parameters
	if err := params.UnmarshalBinary(data[offset : offset+int(paramLen)]); err != nil {
		return fmt.Errorf("failed to unmarshal params: %w", err)
	}
	ek.params = params
	offset += int(paramLen)

	// Read RelinKey
	if len(data) < offset+4 {
		return fmt.Errorf("data too short for RelinKey length")
	}
	relinLen := uint32(data[offset])<<24 | uint32(data[offset+1])<<16 | uint32(data[offset+2])<<8 | uint32(data[offset+3])
	offset += 4
	if len(data) < offset+int(relinLen) {
		return fmt.Errorf("data truncated while reading RelinKey")
	}
	relinKey := new(rlwe.RelinearizationKey)
	if err := relinKey.UnmarshalBinary(data[offset : offset+int(relinLen)]); err != nil {
		return fmt.Errorf("failed to unmarshal relin key: %w", err)
	}
	ek.RelinKey = relinKey
	offset += int(relinLen)

	// Read GaloisKeys
	if len(data) < offset+4 {
		return fmt.Errorf("data too short for GaloisKeys count")
	}
	gkCount := uint32(data[offset])<<24 | uint32(data[offset+1])<<16 | uint32(data[offset+2])<<8 | uint32(data[offset+3])
	offset += 4

	ek.GaloisKeys = make([]*rlwe.GaloisKey, gkCount)
	for i := uint32(0); i < gkCount; i++ {
		if len(data) < offset+4 {
			return fmt.Errorf("data too short for GaloisKey length")
		}
		gkLen := uint32(data[offset])<<24 | uint32(data[offset+1])<<16 | uint32(data[offset+2])<<8 | uint32(data[offset+3])
		offset += 4
		if len(data) < offset+int(gkLen) {
			return fmt.Errorf("data truncated while reading GaloisKey")
		}
		gk := new(rlwe.GaloisKey)
		if err := gk.UnmarshalBinary(data[offset : offset+int(gkLen)]); err != nil {
			return fmt.Errorf("failed to unmarshal galois key: %w", err)
		}
		ek.GaloisKeys[i] = gk
		offset += int(gkLen)
	}

	return nil
}
